// ── 宮位讀取函數 ──
function readPalace(palaceName){
  if(!S.ziwei||!S.ziwei.palaces) return null;
  const GONG_IDX={命宮:0,兄弟:1,夫妻:2,子女:3,財帛:4,疾厄:5,遷移:6,交友:7,官祿:8,田宅:9,福德:10,父母:11};
  const idx=GONG_IDX[palaceName];
  if(idx===undefined) return null;
  const p=S.ziwei.palaces[idx];
  if(!p) return null;
  const majors=p.stars.filter(function(s){return s.type==='major';});
  const minors=p.stars.filter(function(s){return s.type!=='major';});
  const huaLu=p.stars.find(function(s){return s.hua==='化祿';});
  const huaQuan=p.stars.find(function(s){return s.hua==='化權';});
  const huaKe=p.stars.find(function(s){return s.hua==='化科';});
  const huaJi=p.stars.find(function(s){return s.hua==='化忌';});
  const sha=p.stars.filter(function(s){return /火星|鈴星|擎羊|陀羅|地空|地劫/.test(s.name);});
  const bright=majors.length?majors[0].bright:'';
  const isBright=bright==='廟'||bright==='旺';
  const isDark=bright==='落陷'||bright==='不得';
  return {
    name:palaceName, majors:majors.map(function(s){return s.name;}),
    majorFull:majors, bright:bright, isBright:isBright, isDark:isDark,
    huaLu:huaLu, huaQuan:huaQuan, huaKe:huaKe, huaJi:huaJi,
    sha:sha.map(function(s){return s.name;}), hasSha:sha.length>0,
    branch:p.branch||''
  };
}

// ── 白話翻譯函數：讀宮位 → 查句庫 → 輸出白話 ──

// ═══════════════════════════════════════════════════════════════════
// 升級版 talkPalace — 支援星曜組合解讀
// 替換原本的 talkPalace 函數
// ═══════════════════════════════════════════════════════════════════

function talkPalace(palaceName){
  const r=readPalace(palaceName);
  if(!r||!r.majors.length) return '';
  
  // ── Step 1: 生成組合 key ──
  // 取所有主星名，按固定順序排列（紫微系在前、天府系在後）
  const STAR_ORDER=['紫微','天機','太陽','武曲','天同','廉貞','天府','太陰','貪狼','巨門','天相','天梁','七殺','破軍'];
  const sortedMajors = r.majors.slice().sort(function(a,b){
    return STAR_ORDER.indexOf(a) - STAR_ORDER.indexOf(b);
  });
  
  // 組合 key: 雙星用 "A+B"，單星就是星名本身
  const comboKey = sortedMajors.length >= 2 
    ? sortedMajors[0] + '+' + sortedMajors[1] 
    : sortedMajors[0];
  
  // ── Step 2: 查組合句庫 ──
  let text = '';
  const comboDict = (typeof STAR_COMBO_TALK !== 'undefined') ? STAR_COMBO_TALK[palaceName] : null;
  
  if(comboDict && comboDict[comboKey]){
    // 命中組合
    text = comboDict[comboKey];
  } else if(comboDict && comboDict[sortedMajors[0]]){
    // 沒有組合但有單星 (fallback)
    text = comboDict[sortedMajors[0]];
  } else {
    // 最後 fallback: 用舊的 STAR_TALK
    const dict = STAR_TALK[palaceName];
    if(dict) text = dict[sortedMajors[0]] || '';
  }
  
  if(!text) return '';

  // ── Step 3: 四化修飾（升級版：區分組合四化 vs 單星四化）──
  // 化祿
  if(r.huaLu){
    const luStarName = r.huaLu.name || '';
    if(HUA_TALK['化祿'] && HUA_TALK['化祿'][palaceName]){
      text += ' ' + HUA_TALK['化祿'][palaceName];
    }
  }
  // 化忌
  if(r.huaJi){
    const jiStarName = r.huaJi.name || '';
    if(HUA_TALK['化忌'] && HUA_TALK['化忌'][palaceName]){
      text += ' 但要注意：' + HUA_TALK['化忌'][palaceName];
    }
  }
  // 化權
  if(r.huaQuan){
    if(HUA_TALK['化權'] && HUA_TALK['化權'][palaceName]){
      text += ' ' + HUA_TALK['化權'][palaceName];
    }
  }
  // 化科
  if(r.huaKe){
    if(HUA_TALK['化科'] && HUA_TALK['化科'][palaceName]){
      text += ' ' + HUA_TALK['化科'][palaceName];
    }
  }
  
  // ── Step 4: 煞星修飾（升級版：具體煞星名稱）──
  if(r.hasSha && r.sha.length > 0){
    const shaNames = r.sha;
    const hasYang = shaNames.includes('擎羊');
    const hasTuo = shaNames.includes('陀羅');
    const hasHuo = shaNames.includes('火星');
    const hasLing = shaNames.includes('鈴星');
    const hasDiKong = shaNames.includes('地空');
    const hasDiJie = shaNames.includes('地劫');
    
    if(palaceName === '夫妻'){
      if(hasYang) text += ' 擎羊入夫妻宮，感情容易有衝突和爭吵，但吵完反而更了解彼此。';
      else if(hasTuo) text += ' 陀羅入夫妻宮，感情上容易拖泥帶水、糾纏不清。果斷一點反而好。';
      else if(hasHuo||hasLing) text += ' 火鈴入夫妻宮，感情來得快也可能去得快。激情之後記得經營日常。';
      else if(hasDiKong||hasDiJie) text += ' 空劫入夫妻宮，感情上有「說不出的空虛感」。精神層面的交流比物質更重要。';
      else text += ' 感情路上會有些衝突和考驗，但磨合過了反而更牢固。';
    } else if(palaceName === '官祿'){
      if(hasYang) text += ' 擎羊入官祿宮，事業上競爭激烈但也帶來突破力。你不怕硬仗。';
      else if(hasTuo) text += ' 陀羅入官祿宮，工作進度容易被拖延。學會設deadline逼自己。';
      else if(hasHuo||hasLing) text += ' 火鈴入官祿宮，事業上有突發的機會或變動。反應快的人佔優勢。';
      else if(hasDiKong||hasDiJie) text += ' 空劫入官祿宮，事業上容易有「做白工」的感覺。選對方向比努力更重要。';
      else text += ' 事業上會遇到挑戰，但也帶來衝勁和突破力。';
    } else if(palaceName === '財帛'){
      if(hasYang) text += ' 擎羊入財帛宮，賺錢過程有競爭和壓力。適合靠實力而非運氣賺錢。';
      else if(hasTuo) text += ' 陀羅入財帛宮，收入進度可能比預期慢。耐心等待，該來的會來。';
      else if(hasHuo||hasLing) text += ' 火鈴入財帛宮，財運有突發性——突然賺一筆或突然花一筆。留緊急預備金。';
      else if(hasDiKong||hasDiJie) text += ' 空劫入財帛宮，容易有「錢莫名消失」的感覺。記帳是你最需要的習慣。';
      else text += ' 財務上容易有突發狀況，要留緊急預備金。';
    } else if(palaceName === '疾厄'){
      if(hasYang) text += ' 擎羊入疾厄宮，注意外傷和手術。開車繫安全帶、運動做好保護。';
      else if(hasTuo) text += ' 陀羅入疾厄宮，容易有慢性病或反覆發作的問題。找到根源徹底治療。';
      else if(hasHuo||hasLing) text += ' 火鈴入疾厄宮，注意發炎和突發疾病。身體出現異常信號不要拖。';
      else if(hasDiKong||hasDiJie) text += ' 空劫入疾厄宮，注意精神層面的健康——焦慮、失眠、莫名不安。適當運動和社交可以改善。';
      else text += ' 身體容易有突發狀況，定期體檢很重要。';
    } else if(palaceName === '遷移'){
      if(hasYang||hasTuo) text += ' 煞星入遷移宮，出門在外容易遇到阻礙或衝突。凡事多留後路。';
      else if(hasHuo||hasLing) text += ' 火鈴入遷移宮，外出運有突發變化。彈性應對比死守計畫好。';
      else if(hasDiKong||hasDiJie) text += ' 空劫入遷移宮，出門容易「空手而回」。出發前先確認目標明確再行動。';
      else text += ' 出門在外注意安全和意外狀況。';
    } else {
      text += ' 這方面有挑戰但也帶來成長的動力。';
    }
  }
  
  // ── Step 5: 亮度修飾（升級版：具體描述）──
  if(r.isBright){
    if(palaceName === '夫妻') text += ' 主星廟旺，感情運的底氣很足。';
    else if(palaceName === '官祿') text += ' 主星廟旺，事業能量充沛，是你的強項。';
    else if(palaceName === '財帛') text += ' 主星廟旺，財運基礎好，方向對了就能累積。';
    else if(palaceName === '疾厄') text += ' 主星廟旺，體質底子好，正常保養就行。';
    else if(palaceName === '遷移') text += ' 主星廟旺，外出發展的條件很好。';
    else text += ' 這方面的能量發揮得好，是你的強項。';
  } else if(r.isDark){
    if(palaceName === '夫妻') text += ' 主星落陷，感情上需要更多耐心和經營。';
    else if(palaceName === '官祿') text += ' 主星落陷，事業發展需要找到對的方向和貴人。';
    else if(palaceName === '財帛') text += ' 主星落陷，財運需要靠後天規劃和紀律來補強。';
    else if(palaceName === '疾厄') text += ' 主星落陷，這方面是你的弱點，需要特別注意保養。';
    else if(palaceName === '遷移') text += ' 主星落陷，外出需要更謹慎，做好準備再行動。';
    else text += ' 這方面先天偏弱，需要後天多努力補強。';
  }
  
  return text;
}



