// ── DaYun talk + GeJu detect + talkBaziFor + talkZiwei + talkMeihua + talkTarot (lines 9452-10539) ──
function talkDayun(bazi, focusType){
  if(!bazi||!bazi.dayun) return {current:'', goodYears:[], badYears:[], nextDy:''};
  const curDy=bazi.dayun.find(function(d){return d.isCurrent;});
  if(!curDy) return {current:'', goodYears:[], badYears:[], nextDy:''};
  
  var currentText='目前大運走'+curDy.gz;
  if(curDy.level) currentText+='（'+curDy.level+'）';
  if(curDy.level&&(curDy.level.includes('吉')&&!curDy.level.includes('凶')||curDy.level==='大吉')){
    currentText+='，運勢有外力助推，做事容易事半功倍';
  } else if(curDy.level&&(curDy.level.includes('凶')||curDy.level.includes('凶')||curDy.level.includes('不利'))){
    currentText+='，運勢有些阻力，適合穩守不宜冒進';
  } else {
    currentText+='，運勢平穩，不特別助力也不特別阻礙';
  }
  currentText+='。';
  
  var thisYear=new Date().getFullYear();
  var goodYears=[], badYears=[];
  if(curDy.liuNian){
    curDy.liuNian.forEach(function(ln){
      if(ln.year>=thisYear && ln.year<=thisYear+5){
        if(ln.level&&(ln.level.includes('吉')||ln.level.includes('大吉')||ln.level==='大吉'||ln.level==='中吉')){
          goodYears.push(ln.year);
        } else if(ln.level&&(ln.level.includes('凶')||ln.level.includes('凶')||ln.level==='小凶'||ln.level==='大凶')){
          badYears.push(ln.year);
        }
      }
    });
  }
  
  // 下一步大運
  var nextDyText='';
  var nextDyIdx=bazi.dayun.indexOf(curDy)+1;
  if(nextDyIdx<bazi.dayun.length){
    var nd=bazi.dayun[nextDyIdx];
    nextDyText='下一步大運'+nd.gz+(nd.level?'（'+nd.level+'）':'');
  }
  
  return {current:currentText, goodYears:goodYears, badYears:badYears, nextDy:nextDyText};
}

// ── 八字十神白話（針對特定問題類型）──
// ═══════════════════════════════════════════════════════════════════
// 八字格局推理系統 — detectGeJu
//
// 從月令十神出發，判定八字格局類型，然後給出格局特有的事業/感情/財運解讀。
// 傳統格局取用原則：
//   1. 看月令藏干的十神（月令為格局之源）
//   2. 天干有無透出（透出則格局成立）
//   3. 格局是否被破（相剋的十神太旺）
// ═══════════════════════════════════════════════════════════════════

function detectGeJu(bazi){
  if(!bazi || !bazi.pillars || !bazi.gods) return null;
  
  var dm = bazi.dm, dmEl = bazi.dmEl;
  var strong = bazi.strong;
  var gods = bazi.gods;
  var pillars = bazi.pillars;
  var ep = bazi.ep || {};
  
  // 月柱天干十神（月干透出什麼）
  var monthGanGod = gods.month ? gods.month.gan : '';
  // 月支藏干十神（月令本氣）
  var monthZhiGods = gods.month ? gods.month.zhi : [];
  var monthMainGod = monthZhiGods[0] || ''; // 月令本氣十神
  
  // 年干、時干的十神
  var yearGanGod = gods.year ? gods.year.gan : '';
  var hourGanGod = gods.hour ? gods.hour.gan : '';
  
  // 所有透出的天干十神
  var allGanGods = [yearGanGod, monthGanGod, hourGanGod].filter(function(g){return g && g!=='日主' && g!=='—';});
  
  // 統計各十神出現次數
  var godStats = {};
  allGanGods.forEach(function(g){ godStats[g] = (godStats[g]||0) + 1; });
  monthZhiGods.forEach(function(g){ if(g && g!=='—') godStats[g] = (godStats[g]||0) + 1; });
  // 加上其他地支藏干
  ['year','day','hour'].forEach(function(p){
    if(gods[p] && gods[p].zhi){
      gods[p].zhi.forEach(function(g){ if(g && g!=='—') godStats[g] = (godStats[g]||0) + 0.5; });
    }
  });
  
  // ── 格局判定邏輯 ──
  var geju = null;
  var gejuType = '';
  var gejuDesc = '';
  var gejuGrade = ''; // 成格、破格、半成
  
  // 先看月令本氣，再看是否天干透出
  var hasTransparent = allGanGods.includes(monthMainGod);
  
  // 月令為比劫（建祿格/陽刃格）
  if(monthMainGod === '比肩' || monthMainGod === '劫財'){
    // 建祿格/月刃格：看其他透出的十神決定取用
    if(godStats['正官'] >= 1 || godStats['七殺'] >= 1){
      gejuType = '建祿用官殺';
      gejuDesc = '月令建祿，天干透官殺為用。你天生有根基、有底氣，事業上適合在體制內發展或被拔擢。';
    } else if(godStats['食神'] >= 1 || godStats['傷官'] >= 1){
      gejuType = '建祿用食傷';
      gejuDesc = '月令建祿，天干透食傷為用。你的才華和表達力是最大的武器，適合靠技術或創意吃飯。';
    } else if(godStats['偏財'] >= 1 || godStats['正財'] >= 1){
      gejuType = '建祿用財';
      gejuDesc = '月令建祿，天干透財星為用。你有根基也有賺錢的動力，適合穩扎穩打地累積財富。';
    } else {
      gejuType = '建祿格';
      gejuDesc = '月令建祿，你天生有底氣和資源，但需要找到一個明確的方向來發揮。';
    }
  }
  // 正官格
  else if(monthMainGod === '正官'){
    gejuType = '正官格';
    if(godStats['傷官'] >= 2){
      gejuGrade = '破格';
      gejuDesc = '正官格但傷官太旺，格局被破。代表你有被管理和規範的機會，但你的叛逆和創意會跟體制衝突。適合在自由度高的環境工作。';
    } else if(godStats['正印'] >= 1 || godStats['偏印'] >= 1){
      gejuGrade = '成格';
      gejuDesc = '正官配印，這是八字裡最經典的好格局之一。代表你有「被提拔、被重用」的命格。適合在大組織裡穩步上升，走管理路線。';
    } else if(godStats['正財'] >= 1 || godStats['偏財'] >= 1){
      gejuGrade = '成格';
      gejuDesc = '正官配財，財生官旺。代表你有能力在職場上靠實績升遷，錢和地位會同步增長。';
    } else {
      gejuGrade = '半成';
      gejuDesc = '正官格，你天生適合有規範的環境——公務體系、大企業、專業機構。穩定是你的強項。';
    }
  }
  // 七殺格
  else if(monthMainGod === '七殺'){
    gejuType = '七殺格';
    if(godStats['食神'] >= 1){
      gejuGrade = '成格';
      gejuDesc = '七殺配食神，「食神制殺」是名格局。代表你有魄力也有智慧，能把壓力轉化為動力。適合競爭激烈的行業，越有挑戰越能發揮。';
    } else if(godStats['正印'] >= 1 || godStats['偏印'] >= 1){
      gejuGrade = '成格';
      gejuDesc = '七殺配印，「殺印相生」也是好格局。代表你有膽識也有背景支撐。適合做需要權威和專業的工作。';
    } else {
      gejuGrade = '半成';
      gejuDesc = '七殺格，你天生有領導力和行動力，但壓力也大。找到「制」住七殺的方法（學歷、專業證照、靠山），你就能翻身。';
    }
  }
  // 食神格
  else if(monthMainGod === '食神'){
    gejuType = '食神格';
    if(godStats['偏財'] >= 1 || godStats['正財'] >= 1){
      gejuGrade = '成格';
      gejuDesc = '食神生財，這是「靠才華賺錢」的經典格局。你的創意、手藝、表達力就是你的搖錢樹。適合自由業、創作、餐飲、教育。';
    } else if(godStats['偏印'] >= 2){
      gejuGrade = '破格';
      gejuDesc = '食神被梟印奪（梟神奪食），格局破損。代表你的才華容易被壓制或自我懷疑。打破心裡的框架是你最重要的功課。';
    } else {
      gejuGrade = '半成';
      gejuDesc = '食神格，你天生有才華和創造力，享受生活、懂吃懂玩。把興趣發展成事業是最好的路線。';
    }
  }
  // 傷官格
  else if(monthMainGod === '傷官'){
    gejuType = '傷官格';
    if(godStats['正印'] >= 1){
      gejuGrade = '成格';
      gejuDesc = '傷官配印，「傷官佩印」是大格局。代表你既有創新的衝勁，又有學識和修養來駕馭它。適合學術、法律、藝術、技術研發。';
    } else if(godStats['偏財'] >= 1 || godStats['正財'] >= 1){
      gejuGrade = '成格';
      gejuDesc = '傷官生財，你的表達力和創新能力是賺錢的利器。適合業務、自媒體、設計、諮詢。口才和腦子就是你的資本。';
    } else if(godStats['正官'] >= 1 && godStats['正印'] < 1){
      gejuGrade = '破格';
      gejuDesc = '傷官見官，格局不穩。代表你容易跟上司或體制起衝突。不是你不好，是你不適合被管。自由的環境更適合你。';
    } else {
      gejuGrade = '半成';
      gejuDesc = '傷官格，你有強烈的表達慾和反叛精神。把這股能量引到正確的方向，你會是很有影響力的人。';
    }
  }
  // 正財格
  else if(monthMainGod === '正財'){
    gejuType = '正財格';
    if(godStats['正官'] >= 1){
      gejuGrade = '成格';
      gejuDesc = '正財配官，「財官雙美」是好格局。代表你有穩定的收入和社會地位。適合金融、管理、經商，走正路越走越寬。';
    } else {
      gejuGrade = '半成';
      gejuDesc = '正財格，你天生財運穩健，靠勤勞和規劃賺錢。不是暴富型，而是細水長流、越來越有的類型。';
    }
  }
  // 偏財格
  else if(monthMainGod === '偏財'){
    gejuType = '偏財格';
    gejuGrade = '半成';
    gejuDesc = '偏財格，你的財運來源多元、社交能力強。適合做生意、業務、投資。你的錢跟「人脈」直接掛鉤——認識越多人、賺越多錢。';
    if(godStats['七殺'] >= 1 || godStats['正官'] >= 1){
      gejuGrade = '成格';
      gejuDesc = '偏財配官殺，你有賺錢的本事也有社會地位。適合做老闆或高階管理。';
    }
  }
  // 正印格
  else if(monthMainGod === '正印'){
    gejuType = '正印格';
    if(godStats['正官'] >= 1){
      gejuGrade = '成格';
      gejuDesc = '正印配官，「官印相生」是八字裡最穩的格局。代表你一路有貴人、有背景支撐。適合學術、公務、大企業，走越穩越好的路線。';
    } else {
      gejuGrade = '半成';
      gejuDesc = '正印格，你天生有貴人運、學習能力強。適合靠學歷和專業吃飯。';
    }
    if(godStats['偏財'] >= 2 || godStats['正財'] >= 2){
      gejuGrade = '破格';
      gejuDesc += ' 但財星太旺克印，代表物質追求可能干擾你的學業或專業發展。不要為了賺快錢而放棄長期累積。';
    }
  }
  // 偏印格
  else if(monthMainGod === '偏印'){
    gejuType = '偏印格';
    gejuGrade = '半成';
    gejuDesc = '偏印格，你思維獨特、有靈感，適合非傳統的領域——藝術、神秘學、技術研究、冷門專業。但容易三分鐘熱度，堅持下去才看得到成果。';
    if(godStats['食神'] >= 1){
      gejuDesc += ' 偏印遇食神（梟神奪食），注意不要讓自我懷疑吃掉你的才華。';
    }
  }
  
  // 如果月令沒有明確格局，嘗試從透出天干找
  if(!gejuType){
    // 找透出最旺的十神
    var sortedGods = Object.keys(godStats).sort(function(a,b){return godStats[b]-godStats[a];});
    var topGod = sortedGods[0] || '';
    if(topGod === '食神' || topGod === '傷官'){
      gejuType = '食傷旺';
      gejuDesc = '食傷旺，你的才華和表達力是最大的優勢。適合靠腦力和創意賺錢。';
    } else if(topGod === '正官' || topGod === '七殺'){
      gejuType = '官殺旺';
      gejuDesc = '官殺旺，你有管理能力和事業心，適合在有組織的環境中發展。';
    } else if(topGod === '偏財' || topGod === '正財'){
      gejuType = '財星旺';
      gejuDesc = '財星旺，你天生有賺錢的嗅覺和動力。';
    } else if(topGod === '正印' || topGod === '偏印'){
      gejuType = '印星旺';
      gejuDesc = '印星旺，你的學習能力和貴人運都不錯。適合靠專業和學歷發展。';
    }
  }
  
  if(!gejuType) return null;
  
  // ── 格局 × 領域交叉解讀 ──
  var readings = {
    career: '', love: '', wealth: '', health: ''
  };
  
  // 事業解讀
  if(gejuType.includes('正官')){
    readings.career = '你的八字格局偏「管理型」，適合在大組織裡穩定發展。官印相生的人升遷靠的是人品和能力，不用刻意經營。';
  } else if(gejuType.includes('七殺')){
    readings.career = '你的八字格局偏「戰將型」，適合競爭激烈的環境。越有壓力越能激發你的潛力，平淡反而讓你退步。';
  } else if(gejuType.includes('食神') || gejuType.includes('食傷')){
    readings.career = '你的八字格局偏「創意型」，靠才華和手藝吃飯最適合你。把興趣變成事業，你會做得又開心又有錢。';
  } else if(gejuType.includes('傷官')){
    readings.career = '你的八字格局偏「改革型」，有強烈的創新衝動。傳統的環境壓不住你，找一個讓你發揮的舞台最重要。';
  } else if(gejuType.includes('正財')){
    readings.career = '你的八字格局偏「穩健型」，靠勤勞和計畫取勝。不搶風頭但做事靠譜，是老闆最信任的類型。';
  } else if(gejuType.includes('偏財')){
    readings.career = '你的八字格局偏「社交型」，人脈就是你的命脈。做生意、拉業務、談合作都是你的強項。';
  } else if(gejuType.includes('正印') || gejuType.includes('印星')){
    readings.career = '你的八字格局偏「學者型」，適合靠專業知識和學歷發展。醫療、法律、教育、研究都適合。';
  } else if(gejuType.includes('偏印')){
    readings.career = '你的八字格局偏「非主流型」，傳統行業未必適合你。冷門專業、自由業、新興領域更能讓你發光。';
  } else if(gejuType.includes('建祿')){
    readings.career = '月令建祿，你天生有根基和底氣。事業的關鍵不在「起步」而在「方向」——選對了就很穩。';
  }
  
  // 感情解讀
  if(gejuType.includes('食神') || gejuType.includes('食傷')){
    readings.love = '食傷旺的人在感情裡表達力強、有魅力，但也容易「說太多」或「要求太多」。學會「只聽不說」有時候更有用。';
  } else if(gejuType.includes('傷官')){
    readings.love = '傷官旺的人在感情裡有強烈的個人主張，容易跟另一半起衝突。你需要的不是聽你話的人，而是能跟你平等對話的人。';
  } else if(gejuType.includes('正官')){
    readings.love = '正官格的人在感情裡偏傳統穩重，對另一半有一定的期待和標準。門當戶對、互相尊重是你的理想模式。';
  } else if(gejuType.includes('七殺')){
    readings.love = '七殺格的人在感情裡來得猛烈。你喜歡有個性有能力的對象，平淡的感情留不住你。但要注意「猛」不等於「好」。';
  } else if(gejuType.includes('偏財')){
    readings.love = '偏財旺的人異性緣好、選擇多，但也容易花心。感情上最大的功課是「選了就專注」。';
  } else if(gejuType.includes('正印') || gejuType.includes('印星')){
    readings.love = '印星旺的人在感情裡偏被動，習慣被照顧。找一個願意主動付出的另一半最適合你。';
  }
  
  // 財運解讀
  if(gejuType.includes('食神') && (godStats['偏財']>=1 || godStats['正財']>=1)){
    readings.wealth = '食神生財的格局，你的才華就是你的提款機。把技能變現的能力是你最大的財運保障。';
  } else if(gejuType.includes('傷官') && (godStats['偏財']>=1 || godStats['正財']>=1)){
    readings.wealth = '傷官生財的格局，你的口才和創新能力能直接變現。業務、自媒體、諮詢都是好的收入管道。';
  } else if(gejuType.includes('正財')){
    readings.wealth = '正財格的人財運穩健，不會大起大落。靠薪水、靠規劃、靠長期投資是最適合你的理財模式。';
  } else if(gejuType.includes('偏財')){
    readings.wealth = '偏財格的人有偏財運，意外收入不少。但「來得快去得也快」，強制儲蓄是你必須養成的習慣。';
  } else if(gejuType.includes('正官') && (godStats['正財']>=1 || godStats['偏財']>=1)){
    readings.wealth = '財官雙美的格局，收入和地位同步增長。你越往上走，錢越不是問題。';
  } else if(strong){
    readings.wealth = '身強能扛大財，可以做較大的投資和生意。但「能扛」不等於「該扛」，風險管理還是要做好。';
  } else {
    readings.wealth = '身弱的人理財要保守，先確保現金流穩定再說投資。你適合「先存再投」的模式。';
  }
  
  return {
    type: gejuType,
    grade: gejuGrade,
    desc: gejuDesc,
    readings: readings,
    godStats: godStats,
    isSuccess: gejuGrade === '上格' || gejuGrade === '中上',
    isBroken: gejuGrade === '下格' || gejuGrade === '破格'
  };
}

function talkBaziFor(bazi, focusType){
  if(!bazi) return '';
  var ep=bazi.ep||{};
  var strong=bazi.strong;
  var texts=[];
  // ★ Bug #41 fix: 補回 dmEl/yinEl 宣告（之前在三合局/三會局分支用到但函式內未宣告，造成 ReferenceError）
  var dmEl = bazi.dmEl || '';
  var _BS_TALK = {木:'水',火:'木',土:'火',金:'土',水:'金'}; // 生我者（印星）
  var yinEl = dmEl ? (_BS_TALK[dmEl] || '') : '';
  
  // ── 特殊格局（從格/化氣格）優先描述 ──
  if(bazi.specialStructure){
    var _ss = bazi.specialStructure;
    texts.push(_ss.desc);
    // 特殊格局的用神忌神提示
    if(_ss.favEls && _ss.favEls.length){
      texts.push('這個格局喜'+_ss.favEls.join('、')+'行方向，忌'+(_ss.unfavEls||[]).join('、')+'行干擾。走對了運特別順，破格則反覆。');
    }
  }
  
  // ── 地支合沖刑害白話 ──
  if(bazi.branchInteractions && bazi.branchInteractions.length){
    bazi.branchInteractions.forEach(function(bi){
      if(bi.type === '三合局' || bi.type === '三會局'){
        if(bi.el === yinEl || bi.el === dmEl){
          texts.push('地支'+bi.desc+'，對你的根基是很大的加持——'+bi.el+'行力量凝聚，底氣足。');
        } else {
          texts.push('地支'+bi.desc+'，'+bi.el+'行的能量在你的命盤裡特別集中。');
        }
      } else if(bi.type === '六沖'){
        if(focusType==='love' && bi.desc.includes('日支')){
          texts.push(bi.desc+'，婚姻宮被沖動，感情上容易有波動和變化。');
        } else if(focusType==='career' && bi.desc.includes('月支')){
          texts.push(bi.desc+'，事業宮被沖，工作環境容易有變動。');
        }
      } else if(bi.isXing && bi.type === '三刑全'){
        texts.push(bi.desc+'，命帶三刑，做事要格外注意法律風險和人際摩擦。');
      }
    });
  }
  
  // ── 先嘗試格局推理 ──
  var geju = detectGeJu(bazi);
  if(geju){
    // 優先用格局 × 領域的特定解讀（更精準）
    if(geju.readings[focusType]){
      texts.push(geju.readings[focusType]);
    } else if(focusType==='love' || focusType==='career' || focusType==='wealth'){
      // 只有感情/事業/財運才 fallback 到通用格局描述
      // 健康/家庭/人際跟格局描述關聯性低，不輸出
      var desc = geju.desc;
      if(desc.length > 80){
        var cut = desc.lastIndexOf('。', 80);
        if(cut > 20) desc = desc.substring(0, cut+1);
      }
      texts.push(desc);
    }
  }
  
  // ── 補充十神百分比分析（作為格局解讀的輔助）──
  if(focusType==='love'){
    var caiXing=(ep['財']||0)+(ep['才']||0);
    var guanXing=(ep['官']||0)+(ep['殺']||0);
    var shiShang=(ep['食']||0)+(ep['傷']||0);
    var pk=bazi.shensha&&(bazi.shensha.includes('桃花')||bazi.shensha.includes('紅鸞')||bazi.shensha.includes('天喜'));
    if(pk) texts.push('命帶桃花星，異性緣底子好');
    // 只在沒有格局感情解讀時才用百分比
    if(!geju || !geju.readings.love){
      if(bazi.gender==='male'){
        if(caiXing>=25) texts.push('財星旺，代表身邊不缺異性緣');
        else if(caiXing<=10) texts.push('財星偏弱，感情需要主動爭取');
      } else {
        if(guanXing>=25) texts.push('官星旺，容易吸引到有能力的對象');
        else if(guanXing<=10) texts.push('官星偏弱，另一半可能需要時間才能遇到');
      }
    }
    // 日支藏干 → 配偶特質
    if(bazi.cangGan && bazi.cangGan.day){
      var dayBrGan=bazi.cangGan.day;
      if(dayBrGan.length){
        var mainGan=dayBrGan[0];
        var ganTrait={'甲':'正直有主見','乙':'溫柔有彈性','丙':'熱情開朗','丁':'細膩浪漫','戊':'穩重踏實','己':'溫和包容','庚':'果斷有魄力','辛':'精緻有品味','壬':'聰明靈活','癸':'內斂感性'};
        if(ganTrait[mainGan]) texts.push('日支藏'+mainGan+'，配偶性格偏'+ganTrait[mainGan]+'的類型');
      }
    }
    // 食傷旺 → 個人魅力來源
    // ★ Bug #42 fix: shiShang 已在 line 3225 宣告，這裡是重複宣告（var hoist 不會錯但邏輯混亂）
    if(shiShang>=20) texts.push('食傷旺，你本身就有吸引異性的魅力和表達力');
    else if(shiShang<=5) texts.push('食傷弱，感情表達比較含蓄，需要學習主動釋放信號');
  } else if(focusType==='career'){
    // 只在沒有格局事業解讀時用百分比
    if(!geju || !geju.readings.career){
      var guan=(ep['官']||0)+(ep['殺']||0);
      var shi=(ep['食']||0)+(ep['傷']||0);
      if(guan>=25) texts.push('官殺旺，有管理能力和事業心');
      if(shi>=25) texts.push('食傷旺，有創造力和表達能力');
      if(strong) texts.push('身強，適合獨當一面、做決策者');
      else texts.push('身弱，適合在團隊中發揮專業，找靠山合作');
    }
  } else if(focusType==='wealth'){
    // 只在沒有格局財運解讀時用百分比
    if(!geju || !geju.readings.wealth){
      var cai=(ep['財']||0)+(ep['才']||0);
      if(cai>=25) texts.push('命帶財星，賺錢能力不差');
      else if(cai<=10) texts.push('財星弱，收入要靠專業能力而非運氣');
      if(strong) texts.push('身強，扛得住大財，可以做較大的投資');
      else texts.push('身弱，財來了要守住，不適合太激進的投資');
    }
  } else if(focusType==='health'){
    var wk=Object.keys(ep).sort(function(a,b){return (ep[a]||0)-(ep[b]||0);})[0]||'土';
    var bodyMap={木:'肝膽、眼睛',火:'心臟、血壓',土:'脾胃、消化',金:'肺部、呼吸道、皮膚',水:'腎臟、泌尿系統'};
    texts.push('五行最弱：'+wk+'行，對應'+(bodyMap[wk]||'脾胃')+'，是你天生比較需要注意的部位');
  } else if(focusType==='relationship'){
    // 人際：看比劫、食傷、官殺的平衡
    var bijie=(ep['比']||0)+(ep['劫']||0);
    var shiShangR=(ep['食']||0)+(ep['傷']||0);
    var guanShaR=(ep['官']||0)+(ep['殺']||0);
    if(!geju || !geju.readings.relationship){
      if(bijie>=25) texts.push('比劫旺，你有很強的同儕吸引力，朋友多但也容易有競爭');
      else if(bijie<=8) texts.push('比劫弱，獨立性強但朋友圈偏小，需要主動經營人脈');
      if(shiShangR>=20) texts.push('食傷旺，表達力好、有親和力，天生有社交魅力');
      else if(shiShangR<=5) texts.push('食傷弱，表達偏含蓄，人際上需要主動釋放善意');
      if(guanShaR>=25) texts.push('官殺旺，容易遇到「管你的人」，人際上有壓力但也有人幫你指路');
    }
    if(bazi.shensha&&bazi.shensha.includes('天乙貴人')) texts.push('命帶天乙貴人，關鍵時刻總有人拉你一把');
    if(bazi.shensha&&bazi.shensha.includes('劫煞')) texts.push('命帶劫煞，注意小人口舌，重要事情留底');
  } else if(focusType==='family'){
    // 家庭：看印星、財星
    var yinXingF=(ep['印']||0)+(ep['梟']||0);
    var caiXingF=(ep['財']||0)+(ep['才']||0);
    if(!geju || !geju.readings.family){
      if(yinXingF>=25) texts.push('印星旺，家庭支持力強，跟長輩關係密切');
      else if(yinXingF<=8) texts.push('印星弱，從小獨立性強，跟家裡的羈絆較淡');
      if(caiXingF>=25) texts.push('財星旺（代表父親），父親對你的人生影響大');
    }
  }
  
  return texts.map(function(t){return t.replace(/[。．.]+$/,'');}).join('。')+(texts.length?'。':'');
}

// ── 3. 梅花易數白話讀取 ──
function talkMeihua(mh, focusType){
  if(!mh||!mh.ty) return '';
  var texts=[];
  var rel=mh.ty.r||'', judge=mh.ty.f||'';
  
  // ── 1. 體用生剋（核心判定）──
  var relMap={
    '用生體':'環境在幫你，有外力支援',
    '體生用':'你在付出能量，注意別過度消耗',
    '體克用':'你掌握主動權，局勢對你有利',
    '用克體':'有外在壓力或阻礙，不能硬來',
    '比和':'局勢平衡，誰先行動誰佔上風'
  };
  var tiEl=mh.tiG?mh.tiG.el:'', yoEl=mh.yoG?mh.yoG.el:'';
  var tiName=mh.tiG?mh.tiG.name:'', yoName=mh.yoG?mh.yoG.name:'';
  texts.push('卦象體卦'+tiName+'('+tiEl+')、用卦'+yoName+'('+yoEl+')，'+(relMap[rel]||rel)+'（'+judge+'）');
  
  // ── 2. 動爻主動/被動 ──
  var dong=mh.dong||1;
  var dongSide=(dong<=3)?'用':'體';
  if(dongSide==='體'){
    texts.push('動爻在體卦（第'+dong+'爻），變化由你主導，你內心想改變');
  } else {
    texts.push('動爻在用卦（第'+dong+'爻），變化來自外在，你是被動接受的一方');
  }
  
  // ── 3. 調用 analyzeMeihua 取完整分析 ──
  var analysis = null;
  try {
    if(typeof analyzeMeihua === 'function') analysis = analyzeMeihua(mh, focusType);
  } catch(e){}
  
  if(analysis){
    // 月令旺衰
    if(analysis.wangShuai && analysis.wangShuai.ti){
      var tiWS = analysis.wangShuai.ti;
      var curMonth = (new Date()).getMonth()+1;
      if(tiWS.level==='旺'||tiWS.level==='相'){
        texts.push(curMonth+'月體卦能量'+tiWS.level+'，你的底氣足，是有力的時機');
      } else if(tiWS.level==='囚'||tiWS.level==='死'){
        texts.push(curMonth+'月體卦能量'+tiWS.level+'，你的狀態偏弱，行動前多準備');
      }
    }
    
    // 互卦過程
    if(analysis.huGua && analysis.huGua.effect){
      texts.push('互卦「'+mh.hu.n+'」顯示過程：'+analysis.huGua.effect);
    }
    
    // 變卦結果
    if(analysis.bianGua && analysis.bianGua.effect){
      texts.push('變卦「'+mh.bian.n+'」顯示結果：'+analysis.bianGua.effect);
    }
    
    // 時間推算
    if(analysis.timing && analysis.timing.speed){
      texts.push('時間推算：'+analysis.timing.speed+(analysis.timing.est?'，應期約在'+analysis.timing.est:''));
    }
    
    // 類型特殊信號
    if(analysis.signals && analysis.signals.length){
      texts.push(analysis.signals[0]);
    }
  }
  
  // ── 4. focusType 專屬解讀（補充 analyzeMeihua 沒覆蓋的）──
  if(focusType==='love'){
    if(rel==='用生體') texts.push('對方對你有好感，在主動靠近你');
    else if(rel==='體生用') texts.push('你在這段感情裡付出較多，注意是否值得');
    else if(rel==='用克體') texts.push('感情有外在壓力或第三方干擾');
    else if(rel==='體克用') texts.push('你在感情裡比較強勢，適度退讓感情更好');
  } else if(focusType==='career'){
    if(rel==='用生體') texts.push('有貴人或好機會主動找上你');
    else if(rel==='用克體') texts.push('職場壓力大，有被壓制的感覺，先韜光養晦');
    else if(rel==='體克用') texts.push('你能掌控工作局面，適合主動出擊');
  } else if(focusType==='wealth'){
    if(rel==='體克用') texts.push('你能掌握財源，這次投資或決策方向正確');
    else if(rel==='用克體') texts.push('有破財風險，保守理財比冒險好');
    else if(rel==='用生體') texts.push('有意外之財或別人帶來的財運');
    else if(rel==='體生用') texts.push('錢在外流，花費大於收入，需要控制');
  } else if(focusType==='health'){
    var organMap={木:'肝膽/神經',火:'心臟/血液',土:'脾胃/消化',金:'肺/皮膚',水:'腎/泌尿'};
    if(rel==='用克體' && organMap[tiEl]){
      texts.push(tiEl+'行受損，注意'+organMap[tiEl]+'方面的健康');
    }
  } else if(focusType==='relationship'){
    if(rel==='用生體') texts.push('對方或周圍的人對你釋出善意，人際能量正流入');
    else if(rel==='體生用') texts.push('你在人際中付出較多，注意是否被消耗');
    else if(rel==='用克體') texts.push('人際上有壓力來源，可能被人針對或誤解');
    else if(rel==='體克用') texts.push('你在社交中掌握主動權，關係走向由你決定');
    else if(rel==='比和') texts.push('人際磁場平衡，雙方勢均力敵，先釋出善意者佔上風');
  } else if(focusType==='family'){
    if(rel==='用生體') texts.push('家人給你很大的支持和愛護');
    else if(rel==='體生用') texts.push('你為家庭付出較多，注意平衡自己的需求');
    else if(rel==='用克體') texts.push('家庭有些壓力或矛盾需要處理');
    else if(rel==='體克用') texts.push('你在家中有話語權，但要留意家人感受');
  }
  
  return texts.slice(0,6).map(function(t){return t.replace(/[。．.]+$/,'');}).join('。')+'。';
}

// ── 4. 塔羅白話讀取 v2.0 ── 引用牌名+花色能量+宮廷牌人物解讀
// ===== [UPGRADE: talkTarot DEEP REWRITE START] =====
// talkTarot 重寫：每句對應規則 × 牌位 × 欄位，不再硬拼 getTarotTypeMeaning
function talkTarot(tarot, focusType){
  if(!tarot||!tarot.drawn||tarot.drawn.length<10) return '';
  var d=tarot.drawn;
  var t=focusType||'general';
  var tf=t==='love'?'love':t==='career'?'career':t==='wealth'?'wealth':t==='health'?'health':t==='relationship'?'love':t==='family'?'love':'core';

  var inter=analyzeTarotInteractions(d, t);
  if(!inter) return '';

  function _fld(i,field){ var c=d[i]; var card=(typeof TAROT!=='undefined')?TAROT[c.id]:c; var tf=field==='love'||field==='career'||field==='wealth'||field==='health'?field:field; if(c.isUp) return (card&&card[field+'Up'])||getTarotTypeMeaning(c.id,true,field)||c.up||''; return (card&&card[field+'Rv'])||getTarotTypeMeaning(c.id,false,field)||c.rv||''; }
  function _ref(i){ return '【'+d[i].n+(d[i].isUp?'正':'逆')+'】'; }
  function _short(s,n){ return (s||'').replace(/[。．.，,]+$/,'').substring(0,n||35); }

  var texts=[];

  // ── 1. 核心局面（規則1+2）：pos[0] {tf} + pos[1] event/core ──
  var seg1=_ref(0)+'代表你目前的狀態：'+_short(_fld(0,tf));
  if(d[1].isUp){
    seg1+='。橫在其中的'+_ref(1)+'是幫助的力量——'+_short(inter.obstacleNature.eventDesc||inter.obstacleNature.coreDesc);
  } else {
    seg1+='。阻礙你的是'+_ref(1)+'（'+inter.obstacleNature.type+'）：'+_short(inter.obstacleNature.eventDesc||inter.obstacleNature.coreDesc);
  }
  if(inter.obstacleNature.elVsCore) seg1+='（'+_short(inter.obstacleNature.elVsCore,40)+')';
  texts.push(seg1);

  // ── 2. 根基→走向（規則3+10）：pos[2] psyche + pos[5] event + timeSignal ──
  var seg2='深層動力'+_ref(2)+'：'+_short(_fld(2,'psyche'));
  seg2+='。近期走向'+_ref(5)+'：'+_short(_fld(5,'event'));
  if(inter.timingSignal.details.length){
    seg2+='（節奏：'+_short(inter.timingSignal.details[0].val,15)+')';
  }
  // 規則3交叉
  if(inter.rootVsGoal.signal==='衝突'||inter.rootVsGoal.signal==='嚴重衝突'){
    seg2+='。注意：根因與意識目標矛盾——'+_short(inter.rootVsGoal.desc,40);
  }
  texts.push(seg2);

  // ── 3. 你 vs 外界（規則4）：pos[6] {tf} + pos[7] {tf} + personUp/Rv + 元素 ──
  var seg3='';
  var selfDesc=_short(_fld(6,tf),25);
  var envDesc=_short(_fld(7,tf),25);
  // 宮廷牌優先用 personUp/Rv
  var envPerson=_fld(7,'person');
  if(envPerson){
    seg3=(t==='love'?'對方':'外界')+_ref(7)+'——'+_short(envPerson,35);
    seg3+='。你自己'+_ref(6)+'：'+selfDesc;
  } else {
    seg3='你'+_ref(6)+'：'+selfDesc+'，'+(t==='love'?'對方':'外界')+_ref(7)+'：'+envDesc;
  }
  // 規則4結論
  seg3+='。'+_short(inter.selfVsExternal.desc,50);
  if(inter.selfVsExternal.elNote) seg3+='（'+_short(inter.selfVsExternal.elNote,40)+')';
  texts.push(seg3);

  // ── 4. 希望恐懼→結果（規則5+1）：pos[8] psyche/risk + pos[9] {tf} + 規則1走向 ──
  var seg4='內心'+_ref(8)+'：'+_short(_fld(8,'psyche'),25);
  var hfRisk=_fld(8,'risk');
  if(hfRisk) seg4+='（盲點：'+_short(hfRisk,20)+')';
  seg4+='。'+_short(inter.hopeFearVsOutcome.desc,35);
  if(d[9].isUp){
    seg4+='。結果'+_ref(9)+'：'+_short(_fld(9,tf));
  } else {
    seg4+='。結果'+_ref(9)+'：'+_short(_fld(9,tf))+'——需要調整';
  }
  // 規則1元素交叉
  if(inter.coreVsOutcome.elNote) seg4+='（'+_short(inter.coreVsOutcome.elNote,40)+')';
  texts.push(seg4);

  // ── 5. 結構洞察（規則6/7/8/9）──
  var seg5Parts=[];
  // 花色（規則7）
  if(inter.suitBalance.desc&&inter.suitBalance.dominant!=='均衡') seg5Parts.push(_short(inter.suitBalance.desc,50));
  // 宮廷牌（規則8）
  if(inter.courtCardProfile.count>=2&&inter.courtCardProfile.profiles.length){
    seg5Parts.push(_short(inter.courtCardProfile.profiles[0],50));
  }
  // 逆位壓力（規則9）
  if(inter.reversalPressure.rvCount>=6) seg5Parts.push('逆位'+inter.reversalPressure.rvCount+'張，能量嚴重受阻');
  else if(inter.reversalPressure.upCount>=8) seg5Parts.push('正位'+inter.reversalPressure.upCount+'張，能量順暢');
  // 規則1核心vs結果
  if(inter.coreVsOutcome.signal==='否極泰來') seg5Parts.push('核心逆位但結果正位——先苦後甜');
  else if(inter.coreVsOutcome.signal==='後期走偏') seg5Parts.push('核心正位但結果逆位——後期需注意');
  if(seg5Parts.length>0) texts.push(seg5Parts.slice(0,2).join('。'));

  // ── v6.0: 敘事弧線 ──
  var _arcRoot=function(c){var CP2={};[0,1,3,4,6,7,8,10,14,17,19,21].forEach(function(id){CP2[id]=1;});[13,15,16,18].forEach(function(id){CP2[id]=-1;});var pol=CP2[c.id]||0;return c.isUp?(pol>=0?'pos':'neg'):(pol>0?'neg':'pos');};
  var aR=_arcRoot(d[2]),aN=_arcRoot(d[5]),aO=_arcRoot(d[9]);
  if(aR==='pos'&&aN==='pos'&&aO==='pos') texts.push('整體弧線一致向好——從根基到走向到結果都是正面訊號');
  else if(aR==='neg'&&aN==='neg'&&aO==='neg') texts.push('弧線一路下行——底層到結果都不樂觀，需要從根本調整');
  else if(aR==='pos'&&aO==='neg') texts.push('注意：條件不錯但結果偏弱，好牌可能打壞');
  else if(aR==='neg'&&aO==='pos') texts.push('先蹲後跳：起點不好但結果看好，過程中有逆轉');

  // ── v6.0: 結果+走向雙重確認 ──
  if(aO===aN&&(aO==='pos'||aO==='neg')){
    texts.push('結果牌與走向牌方向一致'+(aO==='pos'?'（雙重看好，訊號明確）':'（雙重不利，短期宜謹慎）'));
  }

  // ── v6.0: combo ──
  try{
    var _combos=typeof detectTarotCombos==='function'?detectTarotCombos(d):[];
    if(_combos.length){
      texts.push(_combos[0].cards.join('×')+'——'+(_combos[0].message||'').substring(0,60));
    }
  }catch(e){}

  return texts.slice(0,6).map(function(tx){return tx.replace(/[。．.]+$/,'');}).join('。')+'。';
}

