  if(r.trUp){ pos+=1; } if(r.trFinal&&!r.trUp){ neg+=1; }
  
  // ── 第五層：西洋星盤（權重 ×1）──
  if(r.gAsp>r.bAsp+2){ pos+=1; } if(r.bAsp>r.gAsp+2){ neg+=1; }
  
  // ── 第六層：吠陀（權重 ×1.5）──
  if(r.dashaDig==='exalted'||r.dashaDig==='own'){ pos+=1.5; }
