  var whyGood=[], whyBad=[];
  // 宮位領域白話
  var _palaceArea={'夫妻':'感情','官祿':'事業','財帛':'財運','疾厄':'健康','命宮':'整體','僕役':'人際','父母':'家庭','田宅':'家庭','子女':'子女','遷移':'外出發展','福德':'心靈狀態','兄弟':'手足合作'};
  var _pa=_palaceArea[palaceName]||palaceName;
  if(r.dyUp) whyGood.push('目前大運走勢上升，外在環境配合');
  if(r.hasLu) whyGood.push(_pa+'宮化祿能量活躍，機會正在打開');
  if(r.hasQuan) whyGood.push(_pa+'方面化權加持，你有主導權和掌控力');
  if(r.hasKe) whyGood.push('化科入'+_pa+'宮，專業能力和名聲會被看到');
