function inferSemanticCode(tagId, direction, domain) {
  if (SEMANTIC_CODE_MAP[tagId]) return SEMANTIC_CODE_MAP[tagId];
  if (tagId.startsWith('dx_lu_') || tagId.startsWith('ln_lu_'))
    return (domain || 'GENERAL').toUpperCase() + '.TIMING.FAV';
  if (tagId.startsWith('dx_ji_') || tagId.startsWith('ln_ji_'))
    return (domain || 'GENERAL').toUpperCase() + '.TIMING.UNFAV';
  if (tagId.startsWith('double_ji_'))
    return (domain || 'GENERAL').toUpperCase() + '.TIMING.CRISIS';
  if (tagId.startsWith('double_lu_'))
    return (domain || 'GENERAL').toUpperCase() + '.TIMING.GOLDEN';
  if (tagId.startsWith('dy_ln_combo_') || tagId.startsWith('ln_dy_combo_'))
    return 'COMBO.TENGOD.' + (direction === 'pos' ? 'FAV' : direction === 'neg' ? 'UNFAV' : 'MID');
  if (tagId.includes('_hua_lu') || tagId.includes('_hua_quan') || tagId.includes('_hua_ke'))
    return (domain || 'GENERAL').toUpperCase() + '.PALACE.FAV';
  if (tagId.includes('_hua_ji'))
    return (domain || 'GENERAL').toUpperCase() + '.PALACE.UNFAV';
  if (tagId.includes('_star_bright') || tagId.includes('_sf_bright'))
    return (domain || 'GENERAL').toUpperCase() + '.STRUCTURE.FAV';
  if (tagId.includes('_star_dark') || tagId.includes('_sha_heavy'))
    return (domain || 'GENERAL').toUpperCase() + '.STRUCTURE.UNFAV';
  return null;
}

function buildSemanticCodeTable(symbols, sysZh) {
  var table = {};
  Object.keys(symbols).forEach(function(sys) {
    var sym = symbols[sys];
    if (!sym || !sym.rawTags || sym.confidence === 0) return;
    var sysName = sysZh[sys] || sys;
    sym.rawTags.forEach(function(t) {
      var tagId = t.tag || '';
      var dir = t.direction || 'neutral';
      if (dir === 'neutral') return;
      var code = inferSemanticCode(tagId, dir, t.domain);
      if (!code) return;
      if (!table[code]) table[code] = [];
      table[code].push({ sys: sysName, tag: tagId, label: t.label || '', detail: t.detail || '', weight: t.weight || 1, direction: dir });
    });
  });
  return table;
}

