function renderDayunEnhanced(){
  const b=S.bazi; if(!b)return;
  let html='<div class="dayun-tl">';
  b.dayun.forEach((d,i)=>{
    const s2=d.score||0;
    const lvCls=s2>=6?'lv-dj':s2>=3?'lv-zj':s2>=1?'lv-xj':s2>=-1?'lv-p':s2>=-3?'lv-xk':s2>=-6?'lv-zk':'lv-dk';
    const gzClr=s2>=6?'#4ade80':s2>=3?'#60a5fa':s2>=1?'var(--c-gold,#d4af37)':s2>=-1?'var(--c-text,#e8d5b5)':s2>=-3?'#fbbf24':s2>=-6?'#f87171':'#ef4444';
    html+=`<div class="dy-item dy-${lvCls} ${d.isCurrent?'current':''}" onclick="toggleLiuNian(${i})" title="點擊展開流年">
      <span class="dy-gz" style="color:${gzClr}">${d.gz}</span><span class="dy-age">${d.ageStart}-${d.ageEnd}歲</span>
      <span class="dy-lv ${lvCls}">${d.level}</span><div class="gz-sub">${d.god}</div></div>`;
  });
  html+='</div>';
  html+='<div id="liunian-detail" class="mt-md hidden"></div>';
  document.getElementById('d-dayun').innerHTML=html;
}

function toggleLiuNian(dyIdx){
  const el=document.getElementById('liunian-detail');
  const b=S.bazi; if(!b||!b.dayun[dyIdx])return;
  const dy=b.dayun[dyIdx];
  if(el.dataset.openIdx===String(dyIdx)&&!el.classList.contains('hidden')){
    el.classList.add('hidden');return;
  }
  el.dataset.openIdx=dyIdx;
  el.classList.remove('hidden');
  const curYear=new Date().getFullYear();
  let html=`<div class="card" style="padding:var(--sp-md);margin:0">
    <div class="card-title text-sm" style="display:flex;justify-content:space-between;align-items:center">
      <span><i class="fas fa-calendar"></i> ${dy.gz}大運（${dy.ageStart}-${dy.ageEnd}歲）流年明細</span>
      <button onclick="document.getElementById('liunian-detail').classList.add('hidden')" style="background:none;border:none;color:var(--c-text-dim);cursor:pointer;font-size:1rem;padding:0 4px">✕</button>
    </div>`;
  // 紫微大限同期資訊（加入歲數落差提示）
  if(S.ziwei&&S.ziwei.daXian){
    const matchDx=S.ziwei.daXian.find(dx=>dx.ageStart===dy.ageStart||(dy.ageStart>=dx.ageStart&&dy.ageStart<=dx.ageEnd));
    if(matchDx){
      html+=`<p style="font-size:.78rem;color:var(--c-gold);margin-bottom:4px">紫微大限同期：走「${matchDx.palaceName}」宮（${matchDx.level}）`;
      if(matchDx.stars.length) html+=`，主星${matchDx.stars.join('、')}`;
      if(matchDx.hua.length) html+=`。四化：${matchDx.hua.map(h=>h.star+h.hua+'入'+h.palace).join('、')}`;
      html+='</p>';
      // 歲數落差提示
      if(matchDx.ageStart!==dy.ageStart){
        html+=`<p style="font-size:.65rem;color:var(--c-text-dim);margin-bottom:8px;opacity:.7">📌 紫微大限（${matchDx.ageStart}-${matchDx.ageEnd}歲）與八字大運交接期有${Math.abs(dy.ageStart-matchDx.ageStart)}年落差，此處取能量交集區間。</p>`;
      }
    }
  }

  // ═══ 十神戰略轉譯字典 ═══
  const _GOD_STRAT={
    '正官':{theme:'體制適應與建立個人SOP',risk:'框架壓力偏大',action:'善用體制為自己背書，合約行政要細心',elRx:'土/金'},
    '七殺':{theme:'高壓壓力測試',risk:'突發狀況與激烈競爭',action:'直球對決，主動承擔可將殺氣轉為權力。注意情緒與過勞',elRx:'金/水'},
    '正印':{theme:'向內求取、能量蓄積',risk:'想太多而錯失良機',action:'適合進修考照，設定明確決策停損點',elRx:'水/木'},
    '偏印':{theme:'直覺敏銳的非典型期',risk:'過度猜忌導致人際疏離',action:'信第六感，適合企劃研發，但要保持社交',elRx:'水/木'},
    '比肩':{theme:'尋找同溫層與合作夥伴',risk:'過度堅持己見引摩擦',action:'尋求資源互補的合作模式，避免單打獨鬥',elRx:'木/火'},
    '劫財':{theme:'資源重新分配的震盪期',risk:'突發支出或強大競爭對手',action:'主動投資自己（學習/工具），禁止高槓桿投機',elRx:'土/金'},
    '食神':{theme:'才華洋溢的平穩輸出期',risk:'缺乏企圖心流於安逸',action:'順勢做內容創作或產品開發，保持動力',elRx:'木/火'},
    '傷官':{theme:'高耗能的自我突破期',risk:'心直口快引發口舌是非',action:'將銳利能量投入創新改革，三思而後言',elRx:'水/土'},
    '正財':{theme:'穩健收成的務實期',risk:'患得患失的微觀管理',action:'專注本業與記帳理財，優化商業模式',elRx:'木/火'},
    '偏財':{theme:'高槓桿的資源流通期',risk:'財來得快去得也快',action:'資源整合與業務開發，嚴設資金停損點',elRx:'火/土'},
    '劫財/羊刃':{theme:'資源重新分配的震盪期',risk:'突發支出或強大競爭對手',action:'主動投資自己，禁止高槓桿投機',elRx:'土/金'}
  };

  // 流年格子 — 分兩區：今年前後3年直接顯示，其餘收折
  const SHOW_WINDOW=3; // 今年前後各3年
  const curIdx=dy.liuNian.findIndex(ln=>ln.year===curYear);
  const visStart=Math.max(0,(curIdx<0?0:curIdx)-SHOW_WINDOW);
  const visEnd=Math.min(dy.liuNian.length-1,(curIdx<0?dy.liuNian.length-1:curIdx)+SHOW_WINDOW);

  function lnCard(ln,hidden){
    const isCur=ln.year===curYear;
    const ls=ln.score||0;
    const isGood=ls>=1; const isBad=ls<=-1;
    const borderClr=isGood?'#4ade80':isBad?'#f87171':'var(--c-border)';
    const bgClr=isGood?'rgba(74,222,128,.06)':isBad?'rgba(248,113,113,.06)':'var(--c-bg-card)';
    const lvColor=isGood?'#4ade80':isBad?'#f87171':'#999';
    let zwLnTip='';
    if(S.ziwei&&S.ziwei.getLiuNianZw){
      try{const zwLn=S.ziwei.getLiuNianZw(ln.year);if(zwLn&&zwLn.mingPalace)zwLnTip=zwLn.mingPalace;}catch(e){}
    }
    return `<div class="ln-card${hidden?' ln-hidden':''}" style="padding:6px;border:1.5px solid ${isCur?'var(--c-gold)':borderClr};border-radius:var(--r-sm);background:${isCur?'rgba(212,175,55,.08)':bgClr};font-size:.8rem;text-align:center${hidden?';display:none':''}">
      <strong>${ln.year}</strong><br><span class="serif">${ln.gz}</span><br>
      <span class="el-tag el-${ln.el}">${ln.el}</span>
      <span style="font-size:.6rem;font-weight:600;color:${lvColor}">${ln.level}</span><br>
      <span class="text-xs text-muted">${typeof godLabel==='function'?godLabel(ln.god):ln.god}</span>
      ${zwLnTip?'<br><span style="font-size:.6rem;color:var(--c-dim)">紫微:'+zwLnTip+'</span>':''}
      ${isCur?'<br><span class="text-xs text-gold">← 今年</span>':''}
    </div>`;
  }

  const hasBefore=visStart>0;
  const hasAfter=visEnd<dy.liuNian.length-1;

  html+='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(100px,1fr));gap:4px">';
  if(hasBefore){
    html+=`<div style="grid-column:1/-1;text-align:center;margin:2px 0">
      <button onclick="toggleLnGroup(this,'before')" style="font-size:.72rem;color:var(--c-gold);background:rgba(212,175,55,.1);border:1px solid var(--c-gold);border-radius:12px;padding:2px 10px;cursor:pointer">
        ▲ 顯示前${visStart}年（${dy.liuNian[0].year}–${dy.liuNian[visStart-1].year}）
      </button>
    </div>`;
    dy.liuNian.slice(0,visStart).forEach(ln=>{ html+=lnCard(ln,true); });
  }
  dy.liuNian.slice(visStart,visEnd+1).forEach(ln=>{ html+=lnCard(ln,false); });
  if(hasAfter){
    dy.liuNian.slice(visEnd+1).forEach(ln=>{ html+=lnCard(ln,true); });
    html+=`<div style="grid-column:1/-1;text-align:center;margin:2px 0">
      <button onclick="toggleLnGroup(this,'after')" style="font-size:.72rem;color:var(--c-gold);background:rgba(212,175,55,.1);border:1px solid var(--c-gold);border-radius:12px;padding:2px 10px;cursor:pointer">
        ▼ 顯示後${dy.liuNian.length-1-visEnd}年（${dy.liuNian[visEnd+1].year}–${dy.liuNian[dy.liuNian.length-1].year}）
      </button>
    </div>`;
  }
  html+='</div>';

  // ═══ 流年戰略轉譯面板（每年獨立收折）═══
  html+=`<div style="margin-top:8px">
    <div style="font-size:.78rem;color:var(--c-gold);font-weight:600;margin-bottom:6px">♟ 流年戰略解析
      <span style="font-size:.65rem;font-weight:400;opacity:.7">（點擊年份展開）</span>
    </div>
    <div id="ln-strat-list">`;

  // 取紫微大限四化忌
  let _dxJi='';
  if(S.ziwei&&S.ziwei.daXian){
    const _mdx=S.ziwei.daXian.find(dx=>dy.ageStart>=dx.ageStart&&dy.ageStart<=dx.ageEnd);
    if(_mdx&&_mdx.hua){
      const jiH=_mdx.hua.find(h=>h.hua==='化忌');
      if(jiH) _dxJi=jiH.star+'化忌入'+jiH.palace;
    }
  }
  const _favEl=S.bazi&&S.bazi.fav?S.bazi.fav[0]:'木';
  const _elCrystal={'木':'綠幽靈、綠碧璽','火':'紅瑪瑙、紫水晶','土':'黃水晶、虎眼石','金':'白水晶、天鐵','水':'海藍寶、黑曜石'};

  dy.liuNian.forEach(ln=>{
    const god=ln.god||'';
    // 如果找不到精確 key，嘗試回退到相關十神
    const _godFallback={'劫財/羊刃':'劫財','比劫':'比肩','偏官':'七殺','枭神':'偏印','梟神':'偏印','枭':'偏印','梟':'偏印'};
    const strat=_GOD_STRAT[god]||_GOD_STRAT[_godFallback[god]]||null;
    if(!strat){
      // 沒有戰略模板的流年仍然顯示基本資訊，不跳過
      const ls2=ln.score||0;
      const isGood2=ls2>=1;const isBad2=ls2<=-1;
      html+=`<div style="padding:8px 10px;margin-bottom:6px;border-left:3px solid ${isGood2?'#4ade80':isBad2?'#f87171':'var(--c-gold)'};background:rgba(0,0,0,.08);border-radius:0 6px 6px 0;font-size:.78rem;line-height:1.6">`;
      html+=`<strong style="color:var(--c-gold)">${ln.year} ${ln.gz}【${god}】</strong>`;
      html+=`<span style="font-size:.65rem;color:${isGood2?'#4ade80':isBad2?'#f87171':'#999'};margin-left:6px">${ln.level}</span>`;
      html+=`<p style="margin:4px 0;color:var(--c-text-dim)">📋 ${god}年，${isGood2?'整體能量偏正面，可積極把握。':isBad2?'整體能量偏壓力，宜守成避險。':'能量中性，穩步前進。'}</p>`;
      html+='</div>';
      return;
    }
    const isCur=ln.year===curYear;
    const ls=ln.score||0;
    const isGood=ls>=1;const isBad=ls<=-1;
    const rxEls=strat.elRx.split('/');
    const rxCrystal=rxEls.map(e=>(_elCrystal[e]||'')).filter(Boolean).join('、');

    // 每年獨立 details，今年預設展開
    html+=`<details${isCur?' open':''} style="margin-bottom:4px">
      <summary style="cursor:pointer;padding:6px 10px;border-left:3px solid ${isGood?'#4ade80':isBad?'#f87171':'var(--c-gold)'};background:rgba(0,0,0,.12);border-radius:0 6px 6px 0;font-size:.78rem;list-style:none;display:flex;justify-content:space-between;align-items:center">
        <span><strong style="color:var(--c-gold)">${ln.year} ${ln.gz}【${god}】</strong>
          <span style="font-size:.65rem;color:${isGood?'#4ade80':isBad?'#f87171':'#999'};margin-left:6px">${ln.level}</span>
          ${isCur?'<span style="font-size:.6rem;color:var(--c-gold);margin-left:4px">← 今年</span>':''}
        </span>
        <span style="font-size:.62rem;opacity:.5;white-space:nowrap;overflow:hidden;max-width:80px;text-overflow:ellipsis">${strat.theme.slice(0,8)}</span>
      </summary>
      <div style="padding:8px 10px;font-size:.78rem;line-height:1.7;background:rgba(0,0,0,.06);border-radius:0 0 6px 6px">
        <p style="margin:0 0 4px;color:var(--c-text)">📋 <strong>${strat.theme}</strong>。${strat.action}。</p>
        <p style="margin:0 0 4px;color:var(--c-text-dim)">⚠ ${strat.risk}。${_dxJi?'大限'+_dxJi+'，'+(god==='傷官'||god==='七殺'?'口舌與人際衝突風險加重':'外在環境阻力需留意')+'。':''}</p>
        <p style="margin:0;color:var(--c-text-dim)">💎 ${strat.elRx}行 → ${rxCrystal||'對應喜用神水晶'}</p>
      </div>
    </details>`;
  });
  html+='</div></div>';

  html+='</div>';
  el.innerHTML=html;
}

function toggleLnGroup(btn, side){
  const grid = btn.closest('div[style*="grid"]');
  if(!grid) return;
  const hidden = grid.querySelectorAll('.ln-hidden');
  const isHidden = hidden.length > 0 && hidden[0].style.display === 'none';
  hidden.forEach(c => { c.style.display = isHidden ? '' : 'none'; });
  btn.textContent = isHidden
    ? (side==='before' ? '▲ 收起前段年份' : '▼ 收起後段年份')
    : (side==='before' ? '▲ 展開前段年份' : '▼ 展開後段年份');
}

