// ── 水晶商品匹配：AI 回傳的 crystalRec → 找到商品資料 ──
function _findCrystalProduct(name) {
  if (!name) return null;
  var n = name.trim();

  // ★ v33: 動態庫存優先
  var dynamicProds = window._jyCrystalProducts;
  if (dynamicProds && dynamicProds.length) {
    for (var di = 0; di < dynamicProds.length; di++) {
      if (dynamicProds[di].n === n) return dynamicProds[di];
    }
    for (var di2 = 0; di2 < dynamicProds.length; di2++) {
      if (dynamicProds[di2].n.indexOf(n) >= 0 || n.indexOf(dynamicProds[di2].n) >= 0) return dynamicProds[di2];
    }
  }

  // Fallback: REAL_PRODUCTS
  if (typeof REAL_PRODUCTS === 'undefined') return null;
  var elKeys = ['金','木','水','火','土','special','necklace','love_special'];
  for (var i = 0; i < elKeys.length; i++) {
    var prods = REAL_PRODUCTS[elKeys[i]];
    if (!prods) continue;
    for (var j = 0; j < prods.length; j++) {
      if (prods[j].n === n) return prods[j];
    }
  }
  for (var i2 = 0; i2 < elKeys.length; i2++) {
    var prods2 = REAL_PRODUCTS[elKeys[i2]];
    if (!prods2) continue;
    for (var j2 = 0; j2 < prods2.length; j2++) {
      if (prods2[j2].n.indexOf(n) >= 0 || n.indexOf(prods2[j2].n) >= 0) return prods2[j2];
    }
  }
  return null;
}

