// [PATCH v2] 統一維度輸出層 + 七維交叉決策引擎
// 只新增函式，不修改任何現有函式
// ═══════════════════════════════════════════════════════════════════════

// ── helper 1: scoreToDir ──
function scoreToDir(score) {
  if (score >= 60) return 'pos';
  if (score <= 40) return 'neg';
  return 'mid';
}

// ── helper 2: calcConfidenceFromTags ──
function calcConfidenceFromTags(tags) {
  if (!tags || !tags.length) return 20;
  var totalW = 0, consistW = 0;
  var posW = 0, negW = 0;
  tags.forEach(function(t) {
    var w = t.weight || 1;
    totalW += w;
    if (t.direction === 'pos') posW += w;
    else if (t.direction === 'neg') negW += w;
  });
  if (totalW === 0) return 20;
  // 一致性：多數方向佔比越高，confidence 越高
  var dominant = Math.max(posW, negW);
  var consistency = dominant / totalW; // 0~1
  // 樣本量：tags 越多 confidence 越高（上限 1.0）
  var sampleFactor = Math.min(1, tags.length / 8);
  return Math.max(20, Math.min(95, Math.round((consistency * 0.7 + sampleFactor * 0.3) * 100)));
}

// ── helper 3: inferTimingFromTags ──
function inferTimingFromTags(tags) {
  if (!tags || !tags.length) return 'mixed';
  var shortW = 0, longW = 0;
  // short 系統：meihua / tarot，category=timing 的行運類
  // long 系統：bazi / ziwei / natal / name，category=structure
  tags.forEach(function(t) {
    var w = t.weight || 1;
    var sys = t.sys || '';
    var cat = t.category || '';
    if (sys === 'meihua' || sys === 'tarot') shortW += w;
    else if (cat === 'timing' && (sys === 'jyotish' || sys === 'bazi')) shortW += w * 0.7; // 行運也算短期
    else if (cat === 'structure') longW += w;
    else if (sys === 'bazi' || sys === 'ziwei' || sys === 'natal' || sys === 'name') longW += w;
  });
  if (shortW === 0 && longW === 0) return 'mixed';
  if (shortW > longW * 1.5) return 'short';
  if (longW > shortW * 1.5) return 'long';
  return 'mixed';
}

// ── helper 4: normalizeDimResult ──
function normalizeDimResult(dimName, raw) {
  // ★ Bug #40 fix: 之前 raw.score > 0 會把 0 分（極差）當成 50（中性），失去 0 分訊號
  //   修法：改用「是不是合法數字」判斷，0 也是合法 score
  var _hasScore = raw && typeof raw.score === 'number' && !isNaN(raw.score);
  var score = _hasScore ? raw.score : 50;
  var dir = (raw && raw.dir) ? raw.dir : scoreToDir(score);
  var tags = (raw && raw.tags) ? raw.tags : [];
  return {
    dim: dimName,
    score: score,
    dir: dir,
    confidence: calcConfidenceFromTags(tags),
    timing: inferTimingFromTags(tags),
    tags: tags,
    verdict: (raw && raw.verdict) || (dir === 'pos' ? dimName + '偏吉' : dir === 'neg' ? dimName + '有壓力' : dimName + '中性'),
    reason: (raw && raw.reason) || '',
    detail: (raw && raw.detail) || ''
  };
}

