// [PATCH v4] 六維 Dimension Analyzer + safeMidResult + mergeTiming
//   + build7D 回傳值升級 + S._dimResults 接線
//   全部只新增，不刪除任何既有函式
// ═══════════════════════════════════════════════════════════════════════

// ── safeMidResult：缺資料時的安全 fallback ──
function safeMidResult(dimName, reason) {
  return {
    dim: dimName,
    score: 50,
    dir: 'mid',
    confidence: 20,
    timing: 'mixed',
    tags: [],
    verdict: dimName + '資料不足，以中性計',
    reason: reason || '資料不足',
    detail: ''
  };
}

// ── mergeTiming：從 tags 推斷時間偏向 ──
function mergeTiming(tags) {
  if (!tags || !tags.length) return 'mixed';
  var shortW = 0, midW = 0, longW = 0;
  tags.forEach(function(t) {
    var w = t.weight || 1;
    var tm = t.timing || '';
    if (tm === 'short') shortW += w;
    else if (tm === 'long') longW += w;
    else midW += w;
    // sys 隱含推斷
    var sys = t.sys || '';
    if (sys === 'meihua' || sys === 'tarot') shortW += w * 0.5;
    else if (sys === 'bazi' || sys === 'ziwei' || sys === 'name') longW += w * 0.3;
  });
  var max = Math.max(shortW, midW, longW);
  if (max <= 0) return 'mixed';
  if (shortW === max && shortW > midW * 1.3 && shortW > longW * 1.3) return 'short';
  if (longW === max && longW > midW * 1.3 && longW > shortW * 1.3) return 'long';
  if (midW === max && midW > shortW * 1.3 && midW > longW * 1.3) return 'mid';
  return 'mixed';
}

// ── analyzeBaziDimension：八字完整維度 ──
function analyzeBaziDimension(bazi, type) {
  try {
    if (!bazi) return safeMidResult('八字', '八字資料不存在');
    var tags = (typeof analyzeBaziTags === 'function') ? analyzeBaziTags(bazi, type) : [];
    var score = (typeof baziScoreFromTags === 'function') ? baziScoreFromTags(tags) : 50;
    var dir = (typeof scoreToDir === 'function') ? scoreToDir(score) : (score>=60?'pos':score<=40?'neg':'mid');
    var conf = (typeof calcConfidenceFromTags === 'function') ? calcConfidenceFromTags(tags) : 50;

    // 補充大運流年 timing tag
    var curDy = bazi.dayun && bazi.dayun.find(function(d){ return d.isCurrent; });
    var timingTagAdded = false;
    if (curDy) {
      var dyLevel = curDy.level || '';
      // ★ Bug #45 fix: bazi.js 給的 level 是 大吉/中吉/小吉/平穩/小凶/凶/大凶
      //   舊 regex /旺盛|極強|上升|大吉|中吉/ 漏抓「小吉」
      //   舊 regex /低迷|偏弱|大凶|中凶/ 漏抓「小凶」「凶」（用戶大運是「凶」結果被當 mid 誤導 AI）
      var dyDir = /旺盛|極強|上升|大吉|中吉|小吉/.test(dyLevel)
        ? 'pos'
        : /低迷|偏弱|大凶|中凶|小凶|^凶$|，凶|、凶|^凶|凶$/.test(dyLevel)
        ? 'neg'
        : 'mid';
      tags.push({ sys:'bazi', key:'dayun_now', label:'大運'+dyLevel, direction:dyDir, weight:3, timing:'mid', detail:'目前大運 '+curDy.gz+'（'+dyLevel+'）' });
      timingTagAdded = true;
    }

    var keyTags = tags.filter(function(t){ return t.weight >= 3; }).slice(0,4);
    var reason = keyTags.map(function(t){ return t.label; }).join('；') || (dir==='pos'?'先天命局有利':dir==='neg'?'先天命局有壓力':'命局中性');
    var verdict = dir==='pos'?'八字偏向支持':dir==='neg'?'八字條件偏弱':'八字中性';
    var timing = mergeTiming(tags);

    return { dim:'八字', score:score, dir:dir, confidence:conf, timing:timing,
      verdict:verdict, reason:reason, detail:'', tags:tags };
  } catch(e) { return safeMidResult('八字', '八字分析異常：'+e.message); }
}

