    var keyTags = tags.filter(function(t){ return t.weight >= 3; }).slice(0,4);
    var reason = keyTags.map(function(t){ return t.label; }).join('；') || (dir==='pos'?'紫微格局有利':dir==='neg'?'紫微格局有壓力':'紫微中性');
    var verdict = dir==='pos'?'紫微走勢偏吉':dir==='neg'?'紫微走勢偏凶':'紫微走勢中性';
    return { dim:'紫微', score:score, dir:dir, confidence:conf, timing:'long',
      verdict:verdict, reason:reason, detail:'', tags:tags };
