// ══════════════════════════════════════════════════════════════════════
// 🪐 ZIWEI FUN ZONE — 紫微斗數趣味模組
// 三個模組：紫微主調卡 / 決策提醒卡 / 應期節奏卡
// ══════════════════════════════════════════════════════════════════════

function renderZiweiFunZone() {
  try { _renderZwDailySignal(); } catch(e) { console.warn('zwDaily err:', e); }
  try { _renderZwDecisionCard(); } catch(e) { console.warn('zwDecision err:', e); }
  try { _renderZwTimingCard(); } catch(e) { console.warn('zwTiming err:', e); }
}

function _renderZwDailySignal() {
  var container = document.getElementById('zw-daily-signal-content');
  if (!container) return;
  var zw = (typeof S !== 'undefined') ? S.ziwei : null;
  if (!zw || !zw.palaces) { container.innerHTML = '<p class="text-dim">需要先完成出生資料才能計算紫微主調。</p>'; return; }

  // 命宮主星
  var ming = zw.palaces[0];
  var mingStars = ming && ming.stars ? ming.stars.filter(function(s){ return s.type === 'major'; }) : [];
  var mingNames = mingStars.map(function(s){ return s.name + (s.bright ? '(' + s.bright + ')' : ''); }).join('、') || '無主星';

  // 命宮四化
  var huaList = [];
  if (ming && ming.stars) ming.stars.forEach(function(s){
    if (s.hua) huaList.push(s.name + s.hua);
  });

  // 命宮煞星
  var riskStars = ['擎羊','陀羅','火星','鈴星','地空','地劫','天刑'];
  var risks = ming && ming.stars ? ming.stars.filter(function(s){ return riskStars.indexOf(s.name) >= 0; }) : [];

  var tone = '穩定';
  var toneDesc = '命宮能量平穩，今日適合按節奏推進。';
  if (huaList.some(function(h){ return h.indexOf('化祿') >= 0; })) { tone = '財氣旺'; toneDesc = '命宮有化祿，今日做事容易有回報。'; }
  else if (huaList.some(function(h){ return h.indexOf('化忌') >= 0; })) { tone = '壓力大'; toneDesc = '命宮有化忌，今日容易卡在某個環節，放慢節奏。'; }
  else if (risks.length >= 2) { tone = '衝勁強但躁'; toneDesc = '命宮煞星多，行動力強但容易急躁，三思再動。'; }
  else if (mingStars.length >= 2 && risks.length === 0) { tone = '能量充沛'; toneDesc = '命宮主星強且無煞，今日底氣足，適合爭取。'; }

  var h = '';
  h += '<div style="padding:.6rem;background:rgba(212,175,55,.06);border-radius:8px">';
  h += '<p style="font-weight:700;color:var(--c-gold);margin-bottom:.4rem">今日紫微主調：' + tone + '</p>';
  h += '<p style="font-size:.85rem;line-height:1.7;margin:.2rem 0">' + toneDesc + '</p>';
  h += '<p style="font-size:.8rem;color:var(--c-text-dim);margin-top:.4rem">命宮主星：' + mingNames + '</p>';
  if (huaList.length) h += '<p style="font-size:.78rem;color:var(--c-gold);opacity:.7">四化：' + huaList.join('、') + '</p>';
  if (risks.length) h += '<p style="font-size:.78rem;color:#fca5a5;opacity:.8">煞星：' + risks.map(function(s){ return s.name; }).join('、') + '</p>';
  h += '</div>';
  container.innerHTML = h;
}

function _renderZwDecisionCard() {
  var container = document.getElementById('zw-decision-card-content');
  if (!container) return;
  var zw = (typeof S !== 'undefined') ? S.ziwei : null;
  if (!zw) { container.innerHTML = '<p class="text-dim">需要先完成出生資料。</p>'; return; }

  // 找當前大限
  var dx = null;
  if (zw.daXian) dx = zw.daXian.find(function(d){ return d.isCurrent; });

  // 找今年流年
  var year = new Date().getFullYear();
  var ln = null;
  try {
    if (dx && dx.liuNian) ln = dx.liuNian.find(function(y){ return y.year === year; });
  } catch(e){}

  var h = '<div style="padding:.6rem;background:rgba(96,165,250,.06);border-radius:8px">';
  if (dx) {
    h += '<p style="font-weight:700;color:var(--c-gold);margin-bottom:.3rem">十年大限：' + (dx.palaceName || dx.gz || '') + '</p>';
    h += '<p style="font-size:.85rem;line-height:1.7;margin:.2rem 0">你正在走的十年主軸是「' + (dx.palaceName || '') + '」大限' + (dx.ageRange ? '（' + dx.ageRange + '）' : '') + '。</p>';
    if (dx.stars && dx.stars.length) {
      var dxMajors = dx.stars.filter(function(s){ return s.type === 'major'; }).map(function(s){ return s.name; });
      if (dxMajors.length) h += '<p style="font-size:.8rem;color:var(--c-text-dim)">大限主星：' + dxMajors.join('、') + '</p>';
    }
  } else {
    h += '<p style="font-size:.85rem;color:var(--c-text-dim)">大限資料計算中…</p>';
  }
  if (ln) {
    h += '<div style="margin-top:.5rem;padding-top:.5rem;border-top:1px solid rgba(255,255,255,.06)">';
    h += '<p style="font-size:.82rem;color:var(--c-gold)">' + year + '年流年命宮：' + (ln.mingPalace || ln.gz || '') + '</p>';
    h += '</div>';
  }
  h += '</div>';
  container.innerHTML = h;
}

function _renderZwTimingCard() {
  var container = document.getElementById('zw-timing-card-content');
  if (!container) return;
  var zw = (typeof S !== 'undefined') ? S.ziwei : null;
  if (!zw || !zw.palaces) { container.innerHTML = '<p class="text-dim">需要先完成出生資料。</p>'; return; }

  // 遷移宮（6）、官祿宮（8）、財帛宮（4）的四化狀態
  var keyPalaces = [
    { idx: 4, name: '財帛宮' },
    { idx: 8, name: '官祿宮' },
    { idx: 6, name: '遷移宮' }
  ];
  var h = '<div style="padding:.6rem;background:rgba(74,222,128,.04);border-radius:8px">';
  h += '<p style="font-weight:700;color:var(--c-gold);margin-bottom:.4rem">三方宮位節奏</p>';
  keyPalaces.forEach(function(kp) {
    var p = zw.palaces[kp.idx];
    if (!p) return;
    var stars = p.stars || [];
    var majors = stars.filter(function(s){ return s.type === 'major'; }).map(function(s){ return s.name; });
    var hua = stars.filter(function(s){ return s.hua; }).map(function(s){ return s.name + s.hua; });
    var status = '平穩';
    if (hua.some(function(h2){ return h2.indexOf('化祿') >= 0; })) status = '機會活躍';
    else if (hua.some(function(h2){ return h2.indexOf('化忌') >= 0; })) status = '需留意卡點';
    else if (hua.some(function(h2){ return h2.indexOf('化權') >= 0; })) status = '有掌控力';
    h += '<div style="display:flex;justify-content:space-between;align-items:center;padding:.3rem 0;border-bottom:1px solid rgba(255,255,255,.04)">';
    h += '<span style="font-size:.82rem;font-weight:600">' + kp.name + '</span>';
    h += '<span style="font-size:.78rem;color:' + (status === '需留意卡點' ? '#fca5a5' : status === '機會活躍' ? 'var(--c-gold)' : 'var(--c-text-dim)') + '">' + status + '</span>';
    h += '</div>';
    if (majors.length) h += '<div style="font-size:.72rem;color:var(--c-text-muted);padding:.15rem 0 .2rem">' + majors.join('、') + (hua.length ? '（' + hua.join('、') + '）' : '') + '</div>';
  });
  h += '</div>';
  container.innerHTML = h;
}

