    'Mrigashira': { style:'好奇探索型', goodAction:'研究新知、旅行或換環境', avoidMode:'固守成見、拒絕嘗試', lucky:'散步或接觸自然' },
    'Ardra': { style:'情緒風暴型', goodAction:'面對和釋放情緒、寫日記', avoidMode:'壓抑情緒、假裝沒事', lucky:'聽音樂或看一場觸動內心的電影' },
    'Punarvasu': { style:'回歸初心型', goodAction:'修復關係、重新開始某件事', avoidMode:'一直往前衝不回頭看', lucky:'回到熟悉的地方充電' },
    'Pushya': { style:'照顧滋養型', goodAction:'幫助他人、照顧家人', avoidMode:'只顧自己、忽略身邊的人', lucky:'做一頓飯或泡一杯茶' },
