    var structureWeight = horizon==='long' ? 1.24 : horizon==='mid' ? 1.00 : 0.80;
    var labelMap = {love:'感情',career:'事業',wealth:'財運',health:'健康',relationship:'人際',family:'家庭',general:'整體'};
