              var s = dx.ageStart + '-' + dx.ageEnd + '歲' + (dx.palaceName || '');
              if (dx.isCurrent) s += '★當前';
              if (dx.hua && dx.hua.length) {
                s += '(' + dx.hua.map(function(h) { return h.star + h.hua + '→' + h.palace; }).join(',') + ')';
              }
