                subAnswers: _subs.length ? _subs : undefined,
                summary: _smMatch ? _smMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"') : '',
                closing: _clMatch ? _clMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"') : ''
